CREATE EXTENSION IF NOT EXISTS "uuid-ossp";
CREATE TABLE IF NOT EXISTS merchants (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name VARCHAR(255) NOT NULL, email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, phone VARCHAR(20), address TEXT, plan VARCHAR(50) DEFAULT 'starter', active BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS drivers (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), name VARCHAR(255) NOT NULL, email VARCHAR(255) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, phone VARCHAR(20) NOT NULL, vehicle_type VARCHAR(50) DEFAULT 'car', license_plate VARCHAR(20), status VARCHAR(20) DEFAULT 'offline', current_lat DECIMAL(9,6), current_lng DECIMAL(9,6), active BOOLEAN DEFAULT TRUE, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS deliveries (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), merchant_id UUID REFERENCES merchants(id) ON DELETE CASCADE, driver_id UUID REFERENCES drivers(id), pickup_address TEXT NOT NULL, pickup_barcode VARCHAR(100) UNIQUE NOT NULL, status VARCHAR(30) DEFAULT 'pending', total_stops INT NOT NULL DEFAULT 1, total_miles DECIMAL(8,2) DEFAULT 0, base_price DECIMAL(8,2) DEFAULT 5.00, stops_price DECIMAL(8,2) DEFAULT 0, mileage_price DECIMAL(8,2) DEFAULT 0, total_price DECIMAL(8,2) DEFAULT 0, scheduled_at TIMESTAMP, picked_up_at TIMESTAMP, completed_at TIMESTAMP, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS stops (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), delivery_id UUID REFERENCES deliveries(id) ON DELETE CASCADE, stop_order INT NOT NULL, customer_name VARCHAR(255) NOT NULL, customer_phone VARCHAR(20) NOT NULL, address TEXT NOT NULL, tracking_id VARCHAR(50) UNIQUE NOT NULL, qr_code VARCHAR(255), otp VARCHAR(4), status VARCHAR(20) DEFAULT 'pending', proof_type VARCHAR(20), proof_data TEXT, eta_minutes INT, delivered_at TIMESTAMP, notes TEXT, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS driver_locations (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), driver_id UUID REFERENCES drivers(id) ON DELETE CASCADE, delivery_id UUID REFERENCES deliveries(id), lat DECIMAL(9,6) NOT NULL, lng DECIMAL(9,6) NOT NULL, recorded_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS invoices (id UUID PRIMARY KEY DEFAULT uuid_generate_v4(), merchant_id UUID REFERENCES merchants(id) ON DELETE CASCADE, period_start DATE NOT NULL, period_end DATE NOT NULL, total_routes INT DEFAULT 0, total_stops INT DEFAULT 0, total_miles DECIMAL(10,2) DEFAULT 0, subtotal DECIMAL(10,2) DEFAULT 0, tax DECIMAL(10,2) DEFAULT 0, total DECIMAL(10,2) DEFAULT 0, status VARCHAR(20) DEFAULT 'pending', paid_at TIMESTAMP, created_at TIMESTAMP DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_deliveries_merchant ON deliveries(merchant_id);
CREATE INDEX IF NOT EXISTS idx_deliveries_driver ON deliveries(driver_id);
CREATE INDEX IF NOT EXISTS idx_stops_delivery ON stops(delivery_id);
CREATE INDEX IF NOT EXISTS idx_stops_tracking ON stops(tracking_id);
CREATE INDEX IF NOT EXISTS idx_driver_locations_drv ON driver_locations(driver_id);